#include <bits/stdc++.h>
using namespace std;

const int N = 5e4 + 5;

int sta[N][20], stb[N][20];

int querya(int l, int r)
{
    int len = r - l + 1;
    int b = __lg(len);
    return max(sta[l][b], sta[r - (1 << b) + 1][b]);
}

int queryb(int l, int r)
{
    int len = r - l + 1;
    int b = __lg(len);
    return min(stb[l][b], stb[r - (1 << b) + 1][b]);
}

int main()
{
    int n, m;
    cin >> n >> m;
    ios::sync_with_stdio(false);
    cin.tie(0);
    for(int i = 1; i <= n; i++)
        cin >> sta[i][0];
    for(int i = 1; i <= n; i++)
        stb[i][0] = sta[i][0];
    int lgn = __lg(n);
    for(int i = 1; i <= lgn; i++)
    {
        int len = 1 << i, len2 = len / 2;
        for(int j = 1; j + len <= n + 1; j++)
            sta[j][i] = max(sta[j][i - 1], sta[j + len2][i - 1]);
    }
    for(int i = 1; i <= lgn; i++)
    {
        int len = 1 << i, len2 = len / 2;
        for(int j = 1; j + len <= n + 1; j++)
            stb[j][i] = min(stb[j][i - 1], stb[j + len2][i - 1]);
    }

    for(int i = 1; i <= m; i++)
    {
        int l, r;
        cin >> l >> r;
        cout << querya(l, r) - queryb(l, r) << '\n';
    }
    return 0;
}
